// Recuperer les donnees d'entree
const inputData = $input.first().json;

// Generer ou recuperer un session ID
const sessionId = inputData.sessionId || 
                  inputData.chatId || 
                  `session-${Date.now()}`;

// Retourner les donnees avec session ID
return [{
  json: {
    ...inputData,
    sessionId: sessionId
  }
}];
